def _is_baseline_dirty(path):
    for entry in _BASELINE_DIRTY:
        if entry.endswith("/"):
            if path.startswith(entry):
                return True
        elif path == entry:
            return True
    return False


def _repo_root():
    # tests/generated/<task_id>/<thisfile> -> repo root is 3 parents up.
    return pathlib.Path(__file__).resolve().parents[3]


def _changed_paths(root):
    # This cycle's changes = (working-tree diff vs baseline_head_sha) UNION
    # (untracked new files). The baseline SHA scoping is what isolates this
    # cycle from unrelated history; the baseline-dirty exclusion (applied in
    # the test body) isolates it from concurrent pre-existing working-tree work.
    paths = set()
    # tracked modifications/deletions/renames vs baseline
    diff = subprocess.run(
        ["git", "-C", str(root), "diff", "--name-only", _BASELINE_HEAD_SHA],
        capture_output=True,
        text=True,
        check=True,
    ).stdout
    for line in diff.splitlines():
        if line.strip():
            paths.add(line.strip())
    # untracked new files (e.g. the generated test dir, dev-report)
    untracked = subprocess.run(
        ["git", "-C", str(root), "ls-files", "--others", "--exclude-standard"],
        capture_output=True,
        text=True,
        check=True,
    ).stdout
    for line in untracked.splitlines():
        if line.strip():
            paths.add(line.strip())
    return sorted(paths)


def _is_allowed(path):
    return any(
        path == a or path.startswith(a) if a.endswith("/") else path == a
        for a in _ALLOWED_PATHS
    )


def _is_forbidden(path):
    return any(
        path.startswith(f) if f.endswith("/") else path == f
        for f in _FORBIDDEN_PATHS
    )


